arguments.prompt:
You are implementing a shipment tracking Blazor Web App. The project is already scaffolded at `/tmp/sv-3dc31f9f77b54c5ea63e0f7c288fa558/ShipmentTracker/` with Interactive Auto, Global mode and Individual auth (ASP.NET Core Identity with SQLite). It's a two-project setup:
- **Server project**: `ShipmentTracker/ShipmentTracker/`
- **Client project**: `ShipmentTracker/ShipmentTracker.Client/`

The target framework is `net11.0`. Interactive components MUST go in the `.Client` project. Interactive components cannot access EF Core directly — they must use an `IShipmentService` interface with separate server (direct DB) and client (HttpClient) implementations.

## What to implement

### 1. Shared Models (in `.Client` project since both projects need them)

Create `ShipmentTracker.Client/Models/ShipmentStatus.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}
```

Create `ShipmentTracker.Client/Models/ShipmentDto.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}
```

### 2. Service Interface (in `.Client` project)

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null);
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> GetShipmentByIdAsync(int id);
    Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 3. Client-side Service (in `.Client` project, uses HttpClient)

Create `ShipmentTracker.Client/Services/ShipmentClientService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentClientService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = new List<string>();
        if (!string.IsNullOrEmpty(statusFilter)) query.Add($"status={Uri.EscapeDataString(statusFilter)}");
        if (!string.IsNullOrEmpty(searchTerm)) query.Add($"search={Uri.EscapeDataString(searchTerm)}");
        var url = "api/shipments" + (query.Count > 0 ? "?" + string.Join("&", query) : "");
        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        try
        {
            return await http.GetFromJsonAsync<ShipmentDto>($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        }
        catch (HttpRequestException ex) when (ex.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            return null;
        }
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        try
        {
            return await http.GetFromJsonAsync<ShipmentDto>($"api/shipments/{id}");
        }
        catch (HttpRequestException ex) when (ex.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            return null;
        }
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<ShipmentDto>())!;
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = status });
        response.EnsureSuccessStatusCode();
    }
}
```

### 4. Server-side Data Entity

Create `ShipmentTracker/Data/Shipment.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [Required, MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public int Status { get; set; }

    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }

    [Required, MaxLength(200)]
    public string RecipientName { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;
}
```

### 5. Update ApplicationDbContext

Edit `ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);
        builder.Entity<Shipment>(e =>
        {
            e.HasIndex(s => s.TrackingNumber).IsUnique();
        });
    }
}
```

### 6. Server-side Service

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = db.Shipments.AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, true, out var status))
        {
            query = query.Where(s => s.Status == (int)status);
        }

        if (!string.IsNullOrEmpty(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(s =>
                s.TrackingNumber.ToLower().Contains(term) ||
                s.Destination.ToLower().Contains(term) ||
                s.RecipientName.ToLower().Contains(term));
        }

        return await query.OrderByDescending(s => s.CreatedDate)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        var shipment = await db.Shipments.FindAsync(id);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<ShipmentDto> CreateShipmentAsync(ShipmentDto dto)
    {
        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = dto.Origin,
            Destination = dto.Destination,
            Status = (int)ShipmentStatus.Pending,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = dto.EstimatedDelivery,
            RecipientName = dto.RecipientName,
            Description = dto.Description
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return MapToDto(shipment);
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");

        shipment.Status = (int)status;
        if (status == ShipmentStatus.Delivered)
        {
            shipment.ActualDelivery = DateTime.UtcNow;
        }
        await db.SaveChangesAsync();
    }

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description
    };
}
