        <input type="text" class="form-control" placeholder="Search by tracking #, destination, or recipient..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="LoadShipmentsAsync" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipmentsAsync">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="() => showCreateForm = !showCreateForm">
            @(showCreateForm ? "Cancel" : "New Shipment")
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipmentAsync" FormName="CreateShipment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Recipient Name</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-12 mb-2">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="newShipment.Description" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Create</button>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p class="text-muted">No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block" style="width: auto;"
                                    value="@((int)shipment.Status)"
                                    @onchange="e => UpdateStatusAsync(shipment.Id, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@((int)status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string searchTerm = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new() { EstimatedDelivery = DateTime.Today.AddDays(5) };

    protected override async Task OnInitializedAsync()
    {
        await LoadShipmentsAsync();
    }

    private async Task LoadShipmentsAsync()
    {
        shipments = await ShipmentService.GetShipmentsAsync(statusFilter, searchTerm);
    }

    private async Task CreateShipmentAsync()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new ShipmentDto { EstimatedDelivery = DateTime.Today.AddDays(5) };
        showCreateForm = false;
        await LoadShipmentsAsync();
    }

    private async Task UpdateStatusAsync(int id, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusValue))
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, (ShipmentStatus)statusValue);
            await LoadShipmentsAsync();
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
```

**Create** `ShipmentTracker.Client/Pages/TrackShipment.razor`:
```razor
@page "/track"
@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260527-12345)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackAsync" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedTrackingNumber</strong>. Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>

                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@(string.IsNullOrEmpty(shipment.Description) ? "—" : shipment.Description)</dd>

                        <dt>Shipped Date</dt>
                        <dd>@shipment.CreatedDate.ToString("MMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>

            @* Visual progress bar *@
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
                         aria-valuemin="0"
                         aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedTrackingNumber = "";
    private ShipmentDto? shipment;
    private bool searched;
    private bool isLoading;

    private async Task TrackAsync()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        searched = true;
        searchedTrackingNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedTrackingNumber);
        isLoading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackAsync();
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}
