namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null);
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> GetShipmentByIdAsync(int id);
    Task<ShipmentDto> CreateShipmentAsync(ShipmentDto shipment);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentClientService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null, string? searchTerm = null)
    {
        var query = new List<string>();
        if (!string.IsNullOrEmpty(statusFilter)) query.Add($"status={Uri.EscapeDataString(statusFilter)}");
        if (!string.IsNullOrEmpty(searchTerm)) query.Add($"search={Uri.EscapeDataString(searchTerm)}");
        var url = "api/shipments" + (query.Count > 0 ? "?" + string.Join("&", query) : "");
        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
