@attribute [Authorize]
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260527-12345)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackAsync" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@searchedTrackingNumber</strong>. Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span></dd>

                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@(string.IsNullOrEmpty(shipment.Description) ? "—" : shipment.Description)</dd>

                        <dt>Shipped Date</dt>
                        <dd>@shipment.CreatedDate.ToString("MMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>

            @* Visual progress bar *@
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @GetProgressPercent(shipment.Status)%"
                         aria-valuenow="@GetProgressPercent(shipment.Status)"
